const kyc = ($input.first().json?.data || $input.first().json) || {};
const triggerData = $('New KYC Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

const customerIdMatch = fileName.match(/^([A-Z0-9]+)_/i);
const customerId = customerIdMatch ? customerIdMatch[1] : 'Unknown';

const fullName = kyc.fullNameAsShown ||
  [kyc.firstName, kyc.middleName, kyc.lastName].filter(Boolean).join(' ') || 'Unknown';
const fullAddress = [kyc.street, kyc.city, kyc.state, kyc.postalCode, kyc.country]
  .filter(Boolean).join(', ') || 'Not provided';

let discrepancies = [];
let riskLevel = 'Low';
let verificationStatus = 'Verified';

if (kyc.expirationDate) {
  const exp = new Date(kyc.expirationDate);
  const today = new Date();
  if (exp < today) {
    discrepancies.push('Document expired');
    riskLevel = 'High'; verificationStatus = 'Failed';
  } else if (exp < new Date(today.getTime() + 30*24*60*60*1000)) {
    discrepancies.push('Expires within 30 days');
    if (riskLevel === 'Low') riskLevel = 'Medium';
  }
}
if (!kyc.documentNumber) { discrepancies.push('Missing document number'); riskLevel = 'High'; verificationStatus = 'Review Required'; }
if (!kyc.dateOfBirth)    { discrepancies.push('Missing date of birth');   if (riskLevel === 'Low') riskLevel = 'Medium'; }
const idTypes = ['passport','driver','national id'];
if (idTypes.some(t => (kyc.documentType||'').toLowerCase().includes(t)) && !kyc.photoPresent) {
  discrepancies.push('No photo detected'); riskLevel = 'High'; verificationStatus = 'Review Required';
}
if ((kyc.documentCondition||'').toLowerCase().includes('poor')) {
  discrepancies.push('Poor document quality'); if (riskLevel === 'Low') riskLevel = 'Medium';
}

return [{ json: {
  customerId, documentType: kyc.documentType || 'Unknown',
  fullName, firstName: kyc.firstName || '', lastName: kyc.lastName || '',
  dateOfBirth: kyc.dateOfBirth || 'N/A',
  gender: kyc.gender || 'N/A',
  nationality: kyc.nationality || 'N/A',
  documentNumber: kyc.documentNumber || 'N/A',
  issueDate: kyc.issueDate || 'N/A',
  expirationDate: kyc.expirationDate || 'N/A',
  issuingAuthority: kyc.issuingAuthority || 'N/A',
  issuingCountry: kyc.issuingCountry || 'N/A',
  address: fullAddress,
  photoPresent: kyc.photoPresent ? 'Yes' : 'No',
  signaturePresent: kyc.signaturePresent ? 'Yes' : 'No',
  mrzCode: kyc.mrzCode || 'N/A',
  accountNumber: kyc.accountNumber || 'N/A',
  securityFeatures: kyc.securityFeaturesList || 'Not assessed',
  documentCondition: kyc.documentCondition || 'Good',
  verificationStatus, riskLevel,
  discrepancies: discrepancies.join('; ') || 'None',
  discrepancyCount: discrepancies.length,
  fileName, fileId,
  processedAt: new Date().toISOString(),
  documentType: kyc.documentType || "Unknown",
  fileId: fileId,
  riskLevel: riskLevel,
}}];

